from dataclasses import dataclass

@dataclass
class JourneyMapKPI:
    name:      str
    predicted: float   # value assumed in the map
    actual:    float   # measured from production logs
    threshold: float   # acceptable deviation

    def is_accurate(self) -> bool:
        return abs(self.actual - self.predicted) <= self.threshold

    def deviation_pct(self) -> float:
        if self.predicted == 0:
            return float("inf")
        return abs(self.actual - self.predicted) / self.predicted * 100

def audit_journey_map(kpis: list["JourneyMapKPI"]) -> dict:
    accurate = [k for k in kpis if k.is_accurate()]
    drifted  = [k for k in kpis if not k.is_accurate()]
    return {
        "accurate_count": len(accurate),
        "drifted_count":  len(drifted),
        "drifted_kpis":   [k.name for k in drifted],
        "update_required": len(drifted) > 0,
    }
